SELECT goal_description
FROM project_goals
WHERE goal_threshold_low > 1000;

SELECT goal_description
FROM project_goals
ORDER BY goal_description;

SELECT DISTINCT goal_description
FROM project_goals
ORDER BY goal_description;

SELECT goal_description
FROM project_goals
WHERE goal_id IN (0, 1);

SELECT goal_description
FROM project_goals
WHERE goal_id = 1;

SELECT goal_id, AVG(average_budget_spent) AS avg_budget_spent
FROM project_metrics
WHERE goal_id = 1;

SELECT goal_description
FROM project_goals
ORDER BY goal_id ASC;

SELECT COUNT(*) AS failure_count
  FROM project_failures
 WHERE reason = 'Budget Overrun';
